function solve(n, edges, k) {
    // Sort edges by time in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Find the maximum time
    let maxTime = edges.length > 0 ? edges[edges.length - 1][2] : 0;

    // Binary search for the minimal t
    let low = 0, high = maxTime, answer = maxTime;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let count = countComponents(n, edges, mid);
        if (count >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

function countComponents(n, edges, t) {
    let parent = Array(n).fill(0).map((_, i) => i);
    let rank = Array(n).fill(0);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        let rootU = find(u);
        let rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else {
                parent[rootU] = rootV;
                if (rank[rootU] === rank[rootV]) {
                    rank[rootV]++;
                }
            }
        }
    }

    for (let edge of edges) {
        let u = edge[0], v = edge[1], time = edge[2];
        if (time > t) {
            union(u, v);
        }
    }

    let roots = new Set();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }

    return roots.size;
}

